import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '@/lib/supabase'
import { fireFlowerConfetti } from '@/lib/confetti'
import { unlockAchievement } from '@/lib/achievements'
import { useProfileStore } from '@/store/useProfileStore'
import { Header } from '@/components/Header'
import { Button } from '@/components/AuthFormPrimitives'

// Onboarding laut CLAUDE.md §9 — 4 Slides, Modus-Auswahl entfällt im MVP.
//
// Slide 1: Welcome + Confetti + first_flower-Achievement
// Slide 2: Tagesziel (50 / 100 / 200 / 400 XP)
// Slide 3: Reminder-Zeit (optional, kann übersprungen werden)
// Slide 4: Level-1 Begrüßung → /home

const GOALS = [50, 100, 200, 400]

export default function Onboarding() {
  const [step, setStep] = useState(0)
  const [goal, setGoal] = useState(100)
  const [reminderTime, setReminderTime] = useState('19:00')
  const [reminderEnabled, setReminderEnabled] = useState(false)
  const [saving, setSaving] = useState(false)
  const navigate = useNavigate()

  // Beim Eintritt auf Slide 1: Confetti + first_flower-Achievement (idempotent).
  // Setze hasOnboarded optimistisch — sonst würde der ProtectedRoute den
  // User auf jeder Sub-Page wieder zurück hierher schicken.
  useEffect(() => {
    if (step !== 0) return
    fireFlowerConfetti()
    void unlockAchievement('first_flower').then(() => {
      useProfileStore.getState().setHasOnboarded(true)
    })
  }, [step])

  async function handleFinish() {
    setSaving(true)
    const { data: { user } } = await supabase.auth.getUser()
    if (user) {
      await supabase
        .from('profiles')
        .update({
          daily_goal_xp: goal,
          notifications_enabled: reminderEnabled,
          reminder_time: reminderEnabled ? reminderTime : null
        })
        .eq('id', user.id)
    }
    setSaving(false)
    navigate('/home', { replace: true })
  }

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}>
      <Header />
      <main
        style={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          padding: '2rem 1.25rem 4rem',
          gap: '1.5rem',
          textAlign: 'center'
        }}
      >
        {step === 0 && <SlideWelcome onNext={() => setStep(1)} />}
        {step === 1 && <SlideGoal goal={goal} setGoal={setGoal} onNext={() => setStep(2)} />}
        {step === 2 && (
          <SlideReminder
            enabled={reminderEnabled}
            setEnabled={setReminderEnabled}
            time={reminderTime}
            setTime={setReminderTime}
            onNext={() => setStep(3)}
            onSkip={() => setStep(3)}
          />
        )}
        {step === 3 && <SlideLevel onFinish={handleFinish} saving={saving} />}

        <div style={{ display: 'flex', gap: 8, marginTop: '1rem' }}>
          {[0, 1, 2, 3].map((i) => (
            <span
              key={i}
              style={{
                width: 8,
                height: 8,
                borderRadius: '50%',
                background: i === step ? 'var(--red)' : 'rgba(0,0,0,0.15)',
                transition: 'background 200ms'
              }}
            />
          ))}
        </div>
      </main>
    </div>
  )
}

function SlideWelcome({ onNext }: { onNext: () => void }) {
  return (
    <>
      <div style={{ fontSize: '5rem' }}>🌺</div>
      <h1 className="app-name" style={{ fontSize: '2rem', color: 'var(--red)', margin: 0 }}>
        Üdvözlünk a Virágnál!
      </h1>
      <p style={{ maxWidth: 380, lineHeight: 1.5 }}>
        <b>Virág</b> heißt auf Ungarisch <i>Blume</i> — herzlichen Glückwunsch,
        du hast soeben dein erstes ungarisches Wort gelernt.
      </p>
      <div
        style={{
          padding: '0.4rem 0.9rem',
          background: 'var(--green)',
          color: 'var(--cream)',
          borderRadius: 999,
          fontSize: '0.85rem',
          fontWeight: 600
        }}
      >
        +50 XP · Achievement freigeschaltet
      </div>
      <div style={{ width: '100%', maxWidth: 360, marginTop: '1rem' }}>
        <Button onClick={onNext}>Weiter</Button>
      </div>
    </>
  )
}

function SlideGoal({ goal, setGoal, onNext }: { goal: number; setGoal: (n: number) => void; onNext: () => void }) {
  return (
    <>
      <div style={{ fontSize: '3rem' }}>🎯</div>
      <h2 className="app-name" style={{ fontSize: '1.6rem', color: 'var(--green)', margin: 0 }}>
        Tagesziel
      </h2>
      <p style={{ maxWidth: 380, opacity: 0.75 }}>
        Wie viele XP möchtest du jeden Tag schaffen?
      </p>
      <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap', justifyContent: 'center', maxWidth: 360 }}>
        {GOALS.map((g) => (
          <button
            key={g}
            onClick={() => setGoal(g)}
            style={{
              padding: '0.7rem 1.2rem',
              fontSize: '1.1rem',
              fontWeight: 700,
              borderRadius: 12,
              cursor: 'pointer',
              border: '2px solid var(--red)',
              background: g === goal ? 'var(--red)' : 'transparent',
              color: g === goal ? 'var(--cream)' : 'var(--red)',
              minWidth: 80,
              transition: 'all 120ms ease-out'
            }}
          >
            {g}
          </button>
        ))}
      </div>
      <p style={{ fontSize: '0.85rem', opacity: 0.6, marginTop: '0.5rem' }}>
        Du kannst das später jederzeit ändern.
      </p>
      <div style={{ width: '100%', maxWidth: 360, marginTop: '1rem' }}>
        <Button onClick={onNext}>Weiter</Button>
      </div>
    </>
  )
}

function SlideReminder({
  enabled,
  setEnabled,
  time,
  setTime,
  onNext,
  onSkip
}: {
  enabled: boolean
  setEnabled: (b: boolean) => void
  time: string
  setTime: (s: string) => void
  onNext: () => void
  onSkip: () => void
}) {
  return (
    <>
      <div style={{ fontSize: '3rem' }}>⏰</div>
      <h2 className="app-name" style={{ fontSize: '1.6rem', color: 'var(--green)', margin: 0 }}>
        Tägliche Erinnerung?
      </h2>
      <p style={{ maxWidth: 380, opacity: 0.75 }}>
        Optional — wir können dich täglich an dein Ziel erinnern.
      </p>
      <label
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          cursor: 'pointer',
          padding: '0.7rem 1rem',
          background: 'var(--white)',
          border: '2px solid var(--red)',
          borderRadius: 12,
          maxWidth: 360,
          width: '100%'
        }}
      >
        <input
          type="checkbox"
          checked={enabled}
          onChange={(e) => setEnabled(e.target.checked)}
          style={{ width: 20, height: 20, accentColor: 'var(--red)' }}
        />
        <span style={{ flex: 1, textAlign: 'left' }}>Erinnerung aktivieren</span>
      </label>
      {enabled && (
        <input
          type="time"
          value={time}
          onChange={(e) => setTime(e.target.value)}
          style={{
            padding: '0.7rem 1rem',
            fontSize: '1.1rem',
            border: '1.5px solid rgba(0,0,0,0.15)',
            borderRadius: 10,
            fontFamily: 'inherit',
            maxWidth: 200
          }}
        />
      )}
      <div style={{ width: '100%', maxWidth: 360, marginTop: '1rem', display: 'flex', flexDirection: 'column', gap: 8 }}>
        <Button onClick={onNext}>Weiter</Button>
        <Button variant="ghost" onClick={onSkip}>Überspringen</Button>
      </div>
    </>
  )
}

function SlideLevel({ onFinish, saving }: { onFinish: () => void; saving: boolean }) {
  return (
    <>
      <div style={{ fontSize: '5rem' }}>🌱</div>
      <h2 className="app-name" style={{ fontSize: '1.8rem', color: 'var(--green)', margin: 0 }}>
        Level 1: Medikus I
      </h2>
      <p style={{ maxWidth: 380, lineHeight: 1.5 }}>
        Du startest als <b>Medikus I</b>. Sammle XP, erreiche dein Tagesziel
        und steige durch die Ränge — von Studi bis Professor.
      </p>
      <div style={{ width: '100%', maxWidth: 360, marginTop: '1rem' }}>
        <Button onClick={onFinish} disabled={saving}>
          {saving ? 'Speichern…' : 'Los geht’s 🚀'}
        </Button>
      </div>
    </>
  )
}
